esqlQuery.esql:
FROM metrics-influxdb.otel-*
// Go runtime goroutine count (gauge)
| WHERE COALESCE(metrics.go_goroutines, go_goroutines) IS NOT NULL
// Get max goroutine count per host over the window
| STATS max_goroutines = MAX(COALESCE(metrics.go_goroutines, go_goroutines))
  BY host.name
// Alert when goroutines exceed threshold (e.g. 10000)
// High count may indicate leak; adjust for your baseline
| WHERE max_goroutines > 10000
